mapper.select:
select count(1)
from jst_student_channel_binding
where channel_id = #{channelId}
  and user_id = #{studentUserId}
  and binding_status = 'active'
  and del_flag = '0'

mapper.update:
update jst_student_channel_binding
set binding_status = 'unbound',
    unbind_time = #{updateTime},
    unbind_reason = '渠道方自助解绑',
    update_by = #{updateBy},
    update_time = #{updateTime}
where binding_id = #{bindingId}
  and binding_status = #{expectedStatus}
  and del_flag = '0'
